// Get the output string from the first item
let rawString = $('AI: Create testcases').first().json.output;

// Clean the string by removing the markdown fences
let cleanedString = rawString.replace('```json\n', '').replace('\n```', '');

// Parse the cleaned string into a real JSON array
let jsonData = JSON.parse(cleanedString);

// Return the array for the next node to use
return {
  json: {
    result: jsonData
  }
};

const newItems = [];
for (const item of items) {
  const newAcc = {
    Acc: {
      Description: item.json["details.acceptanceCriteria"],
      Number: newItems.length + 1
    }
  };
  newItems.push({ json: newAcc });
}
return newItems;

// Get all the rows from the previous node
const allItems = $input.all();

// This variable will hold the TestID of the row we just processed
let previousTestID = null;

// Loop through each item (row) one by one
for (const item of allItems) {
  const currentTestID = item.json.TestID;

  // Check if the current row's TestID is the same as the previous one,
  // and make sure it's not empty.
  if (currentTestID && currentTestID === previousTestID) {
    // If it's a match, it's a subsequent step in the same test case.
    // We will clear the redundant columns for this row.
    item.json.TestID = '';
    item.json.Scenario = '';
    item.json.Preconditions = '';
    item.json['Acceptance criteria'] = ''; // Use bracket notation for keys with spaces
  }

  // After processing the row, update previousTestID for the next loop iteration.
  // We only update it if the current TestID is not empty.
  if (currentTestID) {
    previousTestID = currentTestID;
  }
}

// Return all the items, now with the repeating values cleaned up.
return allItems;
